import{_ as l,p as i,q as e,a1 as a}from"./framework-5866ffd3.js";const r={},h=a('<h1 id="案例分析" tabindex="-1"><a class="header-anchor" href="#案例分析" aria-hidden="true">#</a> 案例分析</h1><ul><li>MySQL CPU利用率过高，一般都是慢SQL导致</li><li>数据库非常忙的时候，执行任何一个SQL都很慢</li></ul><h1 id="开发人员故障总结" tabindex="-1"><a class="header-anchor" href="#开发人员故障总结" aria-hidden="true">#</a> 开发人员故障总结</h1><ul><li>写SQL时仔细评估 <ul><li>你的SQL涉及到的表，它的数据规模是多少？</li><li>你的SQL可能会遍历的数据量是多少？</li><li>尽量地避免写出慢SQL</li></ul></li><li>能不能利用缓存减少数据库查询次数？ <ul><li>注意缓存命中率</li></ul></li></ul><h1 id="架构方面" tabindex="-1"><a class="header-anchor" href="#架构方面" aria-hidden="true">#</a> 架构方面</h1><ul><li>上线定时监控和杀掉慢SQL的脚本</li><li>做简单的静态页面首页作为降级方案</li></ul><h1 id="小结" tabindex="-1"><a class="header-anchor" href="#小结" aria-hidden="true">#</a> 小结</h1><ul><li>根据故障时段在系统忙时，推断出故障是跟支持用户访问的功能有关</li><li>根据系统能在流量峰值过后自动恢复这一现象，排除后台服务被大量请求打死的可能性</li><li>根据CPU利用率曲线的规律变化，推断出可能和定时任务有关</li></ul>',8),t=[h];function d(n,c){return i(),e("div",null,t)}const u=l(r,[["render",d],["__file","08.html.vue"]]);export{u as default};
